export enum ApprovalStatus {
  DRAFT = 'DRAFT',
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED',
  WITHDRAWN = 'WITHDRAWN'
}

export type User = {
  id: string;
  name: string;
  position: string;
  department: string;
  avatar?: string;
};

export type ApprovalLine = {
  id: string;
  user: User;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  comment?: string;
  processedAt?: string;
};

export type DocumentTemplate = {
  id: string;
  name: string;
  description: string;
  icon: string;
};

export type ApprovalDocument = {
  id: string;
  title: string;
  templateId: string;
  content: string;
  author: User;
  status: ApprovalStatus;
  createdAt: string;
  approvalLine: ApprovalLine[];
  referenceUsers: User[];
  attachments: string[];
};

export type TabType = 'dashboard' | 'draft' | 'inbox' | 'outbox' | 'archived';

