import React from 'react';
import { ApprovalDocument, ApprovalStatus } from '../types';

interface DashboardProps {
  documents: ApprovalDocument[];
  onSelectDoc: (doc: ApprovalDocument) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ documents, onSelectDoc }) => {
  const stats = [
    { label: '진행중', value: documents.filter(d => d.status === ApprovalStatus.PENDING).length, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: '승인완료', value: documents.filter(d => d.status === ApprovalStatus.APPROVED).length, color: 'text-green-600', bg: 'bg-green-50' },
    { label: '반려', value: documents.filter(d => d.status === ApprovalStatus.REJECTED).length, color: 'text-red-600', bg: 'bg-red-50' },
    { label: '대기중인 결재', value: 2, color: 'text-amber-600', bg: 'bg-amber-50' },
  ];

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-2xl font-bold text-slate-800">안녕하세요, 김철수 과장님 👋</h2>
        <p className="text-slate-500">오늘의 결재 현황을 확인하세요.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((stat, i) => (
          <div key={i} className={`${stat.bg} p-6 rounded-2xl border border-white shadow-sm transition-transform hover:scale-[1.02]`}>
            <p className="text-sm font-medium text-slate-600">{stat.label}</p>
            <p className={`text-3xl font-bold mt-2 ${stat.color}`}>{stat.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white rounded-2xl p-6 border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold text-slate-800">최근 결재 문서</h3>
            <button className="text-sm text-blue-600 font-medium hover:underline">전체보기</button>
          </div>
          <div className="divide-y divide-slate-100">
            {documents.slice(0, 5).map((doc) => (
              <div 
                key={doc.id} 
                onClick={() => onSelectDoc(doc)}
                className="py-4 flex items-center justify-between hover:bg-slate-50 cursor-pointer rounded-lg px-2 transition-colors"
              >
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-lg bg-slate-100 flex items-center justify-center text-xl">
                    {doc.templateId === 't1' ? '💰' : doc.templateId === 't2' ? '🏖️' : doc.templateId === 't3' ? '✈️' : '📄'}
                  </div>
                  <div>
                    <p className="font-semibold text-slate-900">{doc.title}</p>
                    <p className="text-xs text-slate-500">{new Date(doc.createdAt).toLocaleDateString()} · {doc.author.name}</p>
                  </div>
                </div>
                <span className={`px-3 py-1 rounded-full text-xs font-semibold ${
                  doc.status === ApprovalStatus.APPROVED ? 'bg-green-100 text-green-700' :
                  doc.status === ApprovalStatus.REJECTED ? 'bg-red-100 text-red-700' :
