export default Dashboard;

import React, { useState } from 'react';
import { TEMPLATES } from '../constants';
import { generateDocumentContent } from '../services/geminiService';
import { DocumentTemplate } from '../types';

interface DraftViewProps {
  onSubmit: (title: string, content: string, templateId: string) => void;
}

const DraftView: React.FC<DraftViewProps> = ({ onSubmit }) => {
  const [selectedTemplate, setSelectedTemplate] = useState<DocumentTemplate | null>(null);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [keywords, setKeywords] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleAiAssist = async () => {
    if (!selectedTemplate) return;
    setIsGenerating(true);
    const aiContent = await generateDocumentContent(selectedTemplate.name, keywords);
    setContent(aiContent);
    setIsGenerating(false);
  };

  if (!selectedTemplate) {
    return (
      <div className="space-y-8">
        <h2 className="text-2xl font-bold text-slate-800">결재 양식 선택</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {TEMPLATES.map((t) => (
            <button
              key={t.id}
              onClick={() => setSelectedTemplate(t)}
              className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:border-blue-400 hover:shadow-md transition-all text-left"
            >
              <div className="text-4xl mb-4">{t.icon}</div>
              <h3 className="font-bold text-slate-900 mb-1">{t.name}</h3>
              <p className="text-xs text-slate-500">{t.description}</p>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto bg-white rounded-2xl border border-slate-200 shadow-lg overflow-hidden">
      <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setSelectedTemplate(null)}
            className="p-2 hover:bg-white rounded-lg transition-colors"
          >
            ←
          </button>
          <h2 className="text-lg font-bold text-slate-800">{selectedTemplate.name} 작성</h2>
        </div>
        <div className="flex gap-2">
          <button className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-white rounded-lg border border-slate-200">
            임시저장
          </button>
          <button 
            onClick={() => onSubmit(title, content, selectedTemplate.id)}
            className="px-6 py-2 text-sm font-bold text-white bg-blue-600 hover:bg-blue-700 rounded-lg shadow-sm"
          >
            결재요청
          </button>
        </div>
      </div>

      <div className="p-8 space-y-6">
        <div className="grid grid-cols-[100px_1fr] items-center gap-4">
          <label className="text-sm font-semibold text-slate-500">문서 제목</label>
          <input 
            type="text" 
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="제목을 입력하세요"
            className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
          />
        </div>

        <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100">
          <div className="flex items-center gap-2 mb-3">
            <span className="text-lg">🤖</span>
            <span className="text-sm font-bold text-blue-700">AI 기안 도우미</span>
          </div>
          <div className="flex gap-2">
            <input 
              type="text"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
              placeholder="핵심 키워드를 입력하세요 (예: 노트북 교체, 성능 저하)"
              className="flex-1 text-sm px-4 py-2 rounded-lg border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <button 
              onClick={handleAiAssist}
              disabled={isGenerating || !keywords}
              className={`px-4 py-2 text-sm font-bold rounded-lg ${
                isGenerating || !keywords 
                  ? 'bg-slate-300 text-slate-500 cursor-not-allowed' 
                  : 'bg-blue-600 text-white hover:bg-blue-700'
              }`}
            >
              {isGenerating ? '작성중...' : 'AI 초안 생성'}
            </button>
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-slate-500 block">결재 본문</label>
          <textarea 
            rows={12}
            value={content}
            onChange={(e) => setContent(e.target.value)}
            className="w-full px-4 py-4 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-mono text-sm leading-relaxed"
            placeholder="문서의 세부 내용을 입력하세요."
          />
        </div>

        <div className="flex items-center justify-between pt-6 border-t border-slate-100">
          <div className="flex items-center gap-4">
            <span className="text-sm font-semibold text-slate-500">결재선</span>
            <div className="flex -space-x-2">
              {[1, 2].map(i => (
                <div key={i} className="w-8 h-8 rounded-full bg-slate-200 border-2 border-white flex items-center justify-center text-[10px] font-bold">
                  U{i}
                </div>
              ))}
              <button className="w-8 h-8 rounded-full bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400 hover:border-blue-400 hover:text-blue-500">
                +
              </button>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <input type="checkbox" id="urgent" className="w-4 h-4 text-blue-600" />
            <label htmlFor="urgent" className="text-sm font-medium text-slate-600">긴급결재</label>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DraftView;

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DraftView from './components/DraftView';
import ApprovalDetail from './components/ApprovalDetail';
import { TabType, ApprovalDocument, ApprovalStatus } from './types';
import { MOCK_DOCUMENTS, CURRENT_USER } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [documents, setDocuments] = useState<ApprovalDocument[]>(MOCK_DOCUMENTS);
  const [selectedDoc, setSelectedDoc] = useState<ApprovalDocument | null>(null);

  const handleNewRequest = (title: string, content: string, templateId: string) => {
    const newDoc: ApprovalDocument = {
      id: `doc-${Date.now()}`,
      title,
      content,
      templateId,
      author: CURRENT_USER,
      status: ApprovalStatus.PENDING,
      createdAt: new Date().toISOString(),
      approvalLine: [
        { id: `al-${Date.now()}`, user: { id: 'u2', name: '박부장', position: '부장', department: '기획부' }, status: 'PENDING' }
      ],
      referenceUsers: [],
      attachments: []
    };
    setDocuments([newDoc, ...documents]);
    setActiveTab('outbox');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard documents={documents} onSelectDoc={setSelectedDoc} />;
      case 'draft':
        return <DraftView onSubmit={handleNewRequest} />;
      case 'inbox':
        return (
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm">
            <h2 className="text-2xl font-bold text-slate-800 mb-6">받은 결재함</h2>
            <p className="text-slate-500 italic">결재 대기 중인 문서가 없습니다.</p>
          </div>
        );
      case 'outbox':
      case 'archived':
        const filteredDocs = activeTab === 'archived' 
          ? documents.filter(d => d.status === ApprovalStatus.APPROVED || d.status === ApprovalStatus.REJECTED)
          : documents.filter(d => d.status === ApprovalStatus.PENDING);

        return (
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm">
            <h2 className="text-2xl font-bold text-slate-800 mb-6">
              {activeTab === 'archived' ? '완료 문서함' : '보낸 결재함'}
            </h2>
            <div className="divide-y divide-slate-100">
              {filteredDocs.map((doc) => (
                <div 
                  key={doc.id} 
                  onClick={() => setSelectedDoc(doc)}
                  className="py-4 flex items-center justify-between hover:bg-slate-50 cursor-pointer px-4 rounded-xl"
                >
                  <div>
                    <p className="font-bold text-slate-900">{doc.title}</p>
                    <p className="text-sm text-slate-500">{new Date(doc.createdAt).toLocaleDateString()}</p>
                  </div>
                  <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                    doc.status === ApprovalStatus.APPROVED ? 'bg-green-100 text-green-700' :
                    doc.status === ApprovalStatus.REJECTED ? 'bg-red-100 text-red-700' :
                    'bg-blue-100 text-blue-700'
                  }`}>
                    {doc.status}
                  </span>
                </div>
              ))}
              {filteredDocs.length === 0 && <p className="text-slate-400 py-10 text-center">문서가 없습니다.</p>}
            </div>
          </div>
        );
      default:
        return <div>준비 중입니다.</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans antialiased">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 p-8 overflow-y-auto">
        <header className="flex items-center justify-end mb-8">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-full border border-slate-200 shadow-sm cursor-pointer hover:bg-slate-50 transition-colors">
              <span className="text-lg">🔔</span>
              <span className="bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">2</span>
            </div>
            <div className="h-8 w-[1px] bg-slate-200" />
            <div className="flex items-center gap-3">
              <div className="text-right">
                <p className="text-sm font-bold text-slate-900">김철수 과장</p>
                <p className="text-xs text-slate-500">기획부</p>
              </div>
              <img 
                src={CURRENT_USER.avatar} 
                alt="Profile" 
                className="w-10 h-10 rounded-full border-2 border-white shadow-sm"
              />
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>

      {selectedDoc && (
        <ApprovalDetail 
          doc={selectedDoc} 
          onClose={() => setSelectedDoc(null)} 
        />
      )}
    </div>
  );
};

