import React, { useState } from 'react';
import { TEMPLATES } from '../constants';
import { generateDocumentContent } from '../services/geminiService';
import { DocumentTemplate, User, ApprovalLine, ApprovalRole } from '../types';
import UserPicker from './UserPicker';

interface DraftViewProps {
  onSubmit: (title: string, content: string, templateId: string, approvalLine: { user: User, role: ApprovalRole }[], referenceUsers: User[]) => void;
}

const DraftView: React.FC<DraftViewProps> = ({ onSubmit }) => {
  const [selectedTemplate, setSelectedTemplate] = useState<DocumentTemplate | null>(null);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [keywords, setKeywords] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  // Approval Line (Approvers + Agreers)
  const [approvalLine, setApprovalLine] = useState<{ user: User, role: ApprovalRole }[]>([]);
  // Reference Users
  const [referenceUsers, setReferenceUsers] = useState<User[]>([]);

  const [pickerConfig, setPickerConfig] = useState<{ type: 'APPROVER' | 'AGREEMENT' | 'REFERENCE' } | null>(null);

  const handleAiAssist = async () => {
    if (!selectedTemplate) return;
    setIsGenerating(true);
    const aiContent = await generateDocumentContent(selectedTemplate.name, keywords);
    setContent(aiContent);
    setIsGenerating(false);
  };

  const removeFromLine = (userId: string) => {
    setApprovalLine(prev => prev.filter(item => item.user.id !== userId));
  };

  const removeReference = (userId: string) => {
    setReferenceUsers(prev => prev.filter(u => u.id !== userId));
  };

  const onUserSelected = (user: User) => {
    if (!pickerConfig) return;

    if (pickerConfig.type === 'REFERENCE') {
      setReferenceUsers(prev => [...prev, user]);
    } else {
      setApprovalLine(prev => [...prev, { user, role: pickerConfig.type as ApprovalRole }]);
    }
    setPickerConfig(null);
  };

  if (!selectedTemplate) {
    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <h2 className="text-2xl font-bold text-slate-800">결재 양식 선택</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {TEMPLATES.map((t) => (
            <button
              key={t.id}
              onClick={() => setSelectedTemplate(t)}
              className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:border-blue-400 hover:shadow-md transition-all text-left group"
            >
              <div className="text-4xl mb-4 group-hover:scale-110 transition-transform duration-300">{t.icon}</div>
              <h3 className="font-bold text-slate-900 mb-1">{t.name}</h3>
              <p className="text-xs text-slate-500">{t.description}</p>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto bg-white rounded-2xl border border-slate-200 shadow-xl overflow-hidden pb-12">
      <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/80 backdrop-blur-md sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setSelectedTemplate(null)}
            className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-slate-800"
          >
            ←
          </button>
          <h2 className="text-lg font-bold text-slate-800">{selectedTemplate.name} 작성</h2>
        </div>
        <div className="flex gap-2">
          <button className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-white rounded-lg border border-slate-200">
            임시저장
          </button>
          <button 
            onClick={() => {
              const approvers = approvalLine.filter(l => l.role === 'APPROVER');
              if (approvers.length === 0) {
                alert('최소 1명 이상의 최종 결재자를 지정해야 합니다.');
                return;
              }
              onSubmit(title, content, selectedTemplate.id, approvalLine, referenceUsers);
            }}
            className="px-6 py-2 text-sm font-bold text-white bg-blue-600 hover:bg-blue-700 rounded-lg shadow-lg shadow-blue-100 transition-all hover:-translate-y-0.5"
          >
            결재요청
          </button>
        </div>
      </div>

      <div className="p-8 space-y-8">
        {/* Title input */}
        <div className="grid grid-cols-[100px_1fr] items-center gap-4">
          <label className="text-sm font-bold text-slate-400 uppercase tracking-tight">문서 제목</label>
          <input 
            type="text" 
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="제목을 입력하세요"
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-medium transition-all"
          />
        </div>

        {/* AI Assistant */}
        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 p-6 rounded-2xl border border-blue-100 shadow-inner">
          <div className="flex items-center gap-2 mb-4">
            <span className="text-xl">🤖</span>
            <span className="text-sm font-bold text-blue-700">AI 기안 도우미</span>
          </div>
          <div className="flex gap-3">
            <input 
              type="text"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
              placeholder="핵심 키워드를 입력하세요"
              className="flex-1 text-sm px-4 py-3 rounded-xl border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white shadow-sm"
            />
            <button 
              onClick={handleAiAssist}
              disabled={isGenerating || !keywords}
              className={`px-6 py-3 text-sm font-bold rounded-xl transition-all ${
                isGenerating || !keywords 
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                  : 'bg-blue-600 text-white hover:bg-blue-700 shadow-md shadow-blue-100'
              }`}
            >
              {isGenerating ? '작성중...' : 'AI 초안 생성'}
            </button>
          </div>
        </div>

        {/* Content Area */}
        <div className="space-y-3">
          <label className="text-sm font-bold text-slate-400 uppercase tracking-tight block">결재 본문</label>
          <textarea 
            rows={12}
            value={content}
            onChange={(e) => setContent(e.target.value)}
            className="w-full px-6 py-6 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-mono text-sm leading-relaxed min-h-[300px]"
            placeholder="문서의 세부 내용을 입력하세요."
          />
        </div>

        {/* Approval Line Section */}
        <div className="pt-8 border-t border-slate-100">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-tight">결재선 (결재/합의)</h3>
            <div className="flex gap-2">
              <button 
                onClick={() => setPickerConfig({ type: 'AGREEMENT' })}
                className="text-xs font-bold text-amber-600 hover:bg-amber-50 px-3 py-1.5 rounded-lg transition-colors border border-amber-100"
              >
                + 합의자 추가
              </button>
              <button 
                onClick={() => setPickerConfig({ type: 'APPROVER' })}
                className="text-xs font-bold text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors border border-blue-100"
              >
                + 결재자 추가
              </button>
            </div>
          </div>

          <div className="flex flex-wrap gap-4 items-center min-h-[60px] p-4 bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">
            {/* Requester */}
            <div className="flex items-center gap-2 bg-slate-100 px-4 py-2 rounded-xl border border-slate-200 shadow-sm">
              <div className="w-8 h-8 rounded-full bg-slate-300 flex items-center justify-center text-[10px] font-bold">ME</div>
              <div>
                <p className="text-xs font-bold text-slate-900">기안</p>
                <p className="text-[10px] text-slate-500">본인</p>
              </div>
            </div>

            {approvalLine.length > 0 && <span className="text-slate-300 text-xl">→</span>}

            {approvalLine.map((item, index) => (
              <React.Fragment key={item.user.id}>
                <div className={`group relative flex items-center gap-2 px-4 py-2 rounded-xl border shadow-sm transition-all ${
                  item.role === 'AGREEMENT' ? 'bg-amber-50 border-amber-200' : 'bg-white border-blue-200'
                }`}>
                  <div className={`w-8 h-8 rounded-full ${item.role === 'AGREEMENT' ? 'bg-amber-200' : 'bg-blue-100'}`}>
                    <img src={item.user.avatar} alt="" className="w-full h-full rounded-full" />
                  </div>
                  <div>
                    <div className="flex items-center gap-1">
                      <p className="text-xs font-bold text-slate-900">{item.user.name} {item.user.position}</p>
                      <span className={`text-[9px] px-1 rounded font-bold ${
                        item.role === 'AGREEMENT' ? 'bg-amber-200 text-amber-700' : 'bg-blue-100 text-blue-700'
                      }`}>
                        {item.role === 'AGREEMENT' ? '합의' : '결재'}
                      </span>
                    </div>
                    <p className="text-[10px] text-slate-500">{index + 1}차 단계</p>
                  </div>
                  <button 
                    onClick={() => removeFromLine(item.user.id)}
                    className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center text-[10px] opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                  >
                    ✕
                  </button>
                </div>
                {index < approvalLine.length - 1 && <span className="text-slate-300 text-xl">→</span>}
              </React.Fragment>
            ))}

            {approvalLine.length === 0 && (
              <p className="text-sm text-slate-400 italic px-2">결재 단계를 구성해 주세요.</p>
            )}
          </div>
        </div>

        {/* Reference Section */}
        <div className="pt-8 border-t border-slate-100">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-tight">참조자</h3>
            <button 
              onClick={() => setPickerConfig({ type: 'REFERENCE' })}
              className="text-xs font-bold text-slate-600 hover:bg-slate-50 px-3 py-1.5 rounded-lg transition-colors border border-slate-200"
            >
              + 참조자 추가
            </button>
          </div>

          <div className="flex flex-wrap gap-2 items-center min-h-[50px] p-4 bg-slate-50/30 rounded-2xl border border-slate-100">
            {referenceUsers.map((user) => (
              <div key={user.id} className="group relative flex items-center gap-2 bg-white px-3 py-1.5 rounded-full border border-slate-200 shadow-sm">
                <div className="w-6 h-6 rounded-full bg-slate-100">
                  <img src={user.avatar} alt="" className="w-full h-full rounded-full" />
                </div>
                <span className="text-xs font-medium text-slate-700">{user.name} {user.position}</span>
                <button 
                  onClick={() => removeReference(user.id)}
                  className="w-4 h-4 bg-slate-200 text-slate-500 rounded-full flex items-center justify-center text-[10px] hover:bg-red-100 hover:text-red-500 transition-colors"
                >
                  ✕
                </button>
              </div>
            ))}
            {referenceUsers.length === 0 && (
              <p className="text-xs text-slate-400 italic">지정된 참조자가 없습니다.</p>
            )}
          </div>
        </div>
      </div>

      {pickerConfig && (
        <UserPicker 
          onClose={() => setPickerConfig(null)} 
          onSelect={onUserSelected}
          excludeIds={[
            ...approvalLine.map(l => l.user.id),
            ...referenceUsers.map(u => u.id)
          ]}
        />
      )}
    </div>
  );
};

export default DraftView;

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DraftView from './components/DraftView';
import ApprovalDetail from './components/ApprovalDetail';
import { TabType, ApprovalDocument, ApprovalStatus, User, ApprovalLine, ApprovalRole } from './types';
import { MOCK_DOCUMENTS, CURRENT_USER } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [documents, setDocuments] = useState<ApprovalDocument[]>(MOCK_DOCUMENTS);
  const [selectedDoc, setSelectedDoc] = useState<ApprovalDocument | null>(null);

  const handleNewRequest = (
    title: string, 
    content: string, 
    templateId: string, 
    lineItems: { user: User, role: ApprovalRole }[], 
    references: User[]
  ) => {
    const approvalLine: ApprovalLine[] = lineItems.map((item, idx) => ({
      id: `al-${Date.now()}-${item.user.id}-${idx}`,
      user: item.user,
      status: 'PENDING',
      role: item.role
    }));

    const newDoc: ApprovalDocument = {
      id: `APP-${Math.floor(Math.random() * 100000)}`,
      title,
      content,
      templateId,
      author: CURRENT_USER,
      status: ApprovalStatus.PENDING,
      createdAt: new Date().toISOString(),
      approvalLine,
      referenceUsers: references,
      attachments: []
    };

    setDocuments([newDoc, ...documents]);
    setActiveTab('outbox');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard documents={documents} onSelectDoc={setSelectedDoc} />;
      case 'draft':
        return <DraftView onSubmit={handleNewRequest} />;
      case 'inbox':
        return (
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm">
            <h2 className="text-2xl font-bold text-slate-800 mb-6">받은 결재함</h2>
            <p className="text-slate-500 italic">결재 대기 중인 문서가 없습니다.</p>
          </div>
        );
      case 'outbox':
      case 'archived':
        const filteredDocs = activeTab === 'archived' 
          ? documents.filter(d => d.status === ApprovalStatus.APPROVED || d.status === ApprovalStatus.REJECTED)
          : documents.filter(d => d.status === ApprovalStatus.PENDING);

        return (
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm min-h-[500px]">
            <h2 className="text-2xl font-bold text-slate-800 mb-6">
              {activeTab === 'archived' ? '완료 문서함' : '보낸 결재함'}
            </h2>
            <div className="divide-y divide-slate-100">
              {filteredDocs.map((doc) => (
                <div 
                  key={doc.id} 
                  onClick={() => setSelectedDoc(doc)}
                  className="py-4 flex items-center justify-between hover:bg-slate-50 cursor-pointer px-4 rounded-xl transition-all hover:pl-6"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-lg bg-slate-50 flex items-center justify-center text-xl shadow-sm">
                      {doc.templateId === 't1' ? '💰' : doc.templateId === 't2' ? '🏖️' : doc.templateId === 't3' ? '✈️' : '📄'}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-bold text-slate-900">{doc.title}</p>
                        {doc.referenceUsers.length > 0 && (
                          <span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded">참조 {doc.referenceUsers.length}</span>
                        )}
                      </div>
                      <p className="text-sm text-slate-500">{new Date(doc.createdAt).toLocaleDateString()} · {doc.author.name}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      doc.status === ApprovalStatus.APPROVED ? 'bg-green-100 text-green-700' :
                      doc.status === ApprovalStatus.REJECTED ? 'bg-red-100 text-red-700' :
                      'bg-blue-100 text-blue-700'
                    }`}>
                      {doc.status}
                    </span>
                  </div>
                </div>
              ))}
              {filteredDocs.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                  <span className="text-4xl mb-4">📂</span>
                  <p>문서가 없습니다.</p>
                </div>
              )}
            </div>
          </div>
        );
      default:
        return <div>준비 중입니다.</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans antialiased text-slate-900">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 p-8 overflow-y-auto">
        <header className="flex items-center justify-end mb-8">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-full border border-slate-200 shadow-sm cursor-pointer hover:bg-slate-50 transition-colors">
              <span className="text-lg">🔔</span>
              <span className="bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">2</span>
            </div>
            <div className="h-8 w-[1px] bg-slate-200" />
            <div className="flex items-center gap-3">
              <div className="text-right">
                <p className="text-sm font-bold text-slate-900">{CURRENT_USER.name} {CURRENT_USER.position}</p>
                <p className="text-xs text-slate-500">{CURRENT_USER.department}</p>
              </div>
              <img 
                src={CURRENT_USER.avatar} 
                alt="Profile" 
                className="w-10 h-10 rounded-full border-2 border-white shadow-sm"
              />
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>

      {selectedDoc && (
        <ApprovalDetail 
          doc={selectedDoc} 
          onClose={() => setSelectedDoc(null)} 
        />
      )}
    </div>
  );
};

export default App;

export enum ApprovalStatus {
  DRAFT = 'DRAFT',
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED',
  WITHDRAWN = 'WITHDRAWN'
}

export type User = {
  id: string;
  name: string;
  position: string;
  department: string;
  avatar?: string;
};

export type ApprovalRole = 'APPROVER' | 'AGREEMENT';

export type ApprovalLine = {
  id: string;
  user: User;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  role: ApprovalRole;
  comment?: string;
  processedAt?: string;
};

export type DocumentTemplate = {
  id: string;
  name: string;
  description: string;
  icon: string;
};

export type Attachment = {
  id: string;
  name: string;
  size: number;
  type: string;
  data: string; // base64 string
};

export type ApprovalDocument = {
  id: string;
  title: string;
  templateId: string;
  content: string;
  author: User;
  status: ApprovalStatus;
  createdAt: string;
  approvalLine: ApprovalLine[];
  referenceUsers: User[];
  attachments: Attachment[];
};

export type TabType = 'dashboard' | 'draft' | 'inbox' | 'outbox' | 'archived';

import React, { useState, useRef } from 'react';
import { TEMPLATES } from '../constants';
import { generateDocumentContent } from '../services/geminiService';
import { DocumentTemplate, User, ApprovalRole, Attachment } from '../types';
import UserPicker from './UserPicker';

interface DraftViewProps {
  onSubmit: (title: string, content: string, templateId: string, approvalLine: { user: User, role: ApprovalRole }[], referenceUsers: User[], attachments: Attachment[]) => void;
}

const DraftView: React.FC<DraftViewProps> = ({ onSubmit }) => {
  const [selectedTemplate, setSelectedTemplate] = useState<DocumentTemplate | null>(null);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [keywords, setKeywords] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [approvalLine, setApprovalLine] = useState<{ user: User, role: ApprovalRole }[]>([]);
  const [referenceUsers, setReferenceUsers] = useState<User[]>([]);
  const [attachments, setAttachments] = useState<Attachment[]>([]);

  const [pickerConfig, setPickerConfig] = useState<{ type: 'APPROVER' | 'AGREEMENT' | 'REFERENCE' } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAiAssist = async () => {
    if (!selectedTemplate) return;
    setIsGenerating(true);
    const aiContent = await generateDocumentContent(selectedTemplate.name, keywords);
    setContent(aiContent);
    setIsGenerating(false);
  };

  const removeFromLine = (userId: string) => {
    setApprovalLine(prev => prev.filter(item => item.user.id !== userId));
  };

  const removeReference = (userId: string) => {
    setReferenceUsers(prev => prev.filter(u => u.id !== userId));
  };

  const onUserSelected = (user: User) => {
    if (!pickerConfig) return;
    if (pickerConfig.type === 'REFERENCE') {
      setReferenceUsers(prev => [...prev, user]);
    } else {
      setApprovalLine(prev => [...prev, { user, role: pickerConfig.type as ApprovalRole }]);
    }
    setPickerConfig(null);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (attachments.length + files.length > 3) {
      alert("최대 3개의 파일까지만 첨부할 수 있습니다.");
      return;
    }

    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const newAttachment: Attachment = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          size: file.size,
          type: file.type,
          data: event.target?.result as string
        };
        setAttachments(prev => [...prev, newAttachment]);
      };
      reader.readAsDataURL(file);
    });

    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeAttachment = (id: string) => {
    setAttachments(prev => prev.filter(a => a.id !== id));
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  if (!selectedTemplate) {
    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <h2 className="text-2xl font-bold text-slate-800">결재 양식 선택</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {TEMPLATES.map((t) => (
            <button
              key={t.id}
              onClick={() => setSelectedTemplate(t)}
              className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:border-blue-400 hover:shadow-md transition-all text-left group"
            >
              <div className="text-4xl mb-4 group-hover:scale-110 transition-transform duration-300">{t.icon}</div>
              <h3 className="font-bold text-slate-900 mb-1">{t.name}</h3>
              <p className="text-xs text-slate-500">{t.description}</p>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto bg-white rounded-2xl border border-slate-200 shadow-xl overflow-hidden pb-12">
      <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/80 backdrop-blur-md sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setSelectedTemplate(null)}
            className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-slate-800"
          >
            ←
          </button>
          <h2 className="text-lg font-bold text-slate-800">{selectedTemplate.name} 작성</h2>
        </div>
        <div className="flex gap-2">
          <button className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-white rounded-lg border border-slate-200">
            임시저장
          </button>
          <button 
            onClick={() => {
              const approvers = approvalLine.filter(l => l.role === 'APPROVER');
              if (approvers.length === 0) {
                alert('최소 1명 이상의 최종 결재자를 지정해야 합니다.');
                return;
              }
              onSubmit(title, content, selectedTemplate.id, approvalLine, referenceUsers, attachments);
            }}
            className="px-6 py-2 text-sm font-bold text-white bg-blue-600 hover:bg-blue-700 rounded-lg shadow-lg shadow-blue-100 transition-all hover:-translate-y-0.5"
          >
            결재요청
          </button>
        </div>
      </div>

      <div className="p-8 space-y-8">
        <div className="grid grid-cols-[100px_1fr] items-center gap-4">
          <label className="text-sm font-bold text-slate-400 uppercase tracking-tight">문서 제목</label>
          <input 
            type="text" 
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="제목을 입력하세요"
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-medium transition-all"
          />
        </div>

        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 p-6 rounded-2xl border border-blue-100 shadow-inner">
          <div className="flex items-center gap-2 mb-4">
            <span className="text-xl">🤖</span>
            <span className="text-sm font-bold text-blue-700">AI 기안 도우미</span>
          </div>
          <div className="flex gap-3">
            <input 
              type="text"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
              placeholder="핵심 키워드를 입력하세요"
              className="flex-1 text-sm px-4 py-3 rounded-xl border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white shadow-sm"
            />
            <button 
              onClick={handleAiAssist}
              disabled={isGenerating || !keywords}
              className={`px-6 py-3 text-sm font-bold rounded-xl transition-all ${
                isGenerating || !keywords 
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                  : 'bg-blue-600 text-white hover:bg-blue-700 shadow-md shadow-blue-100'
              }`}
            >
              {isGenerating ? '작성중...' : 'AI 초안 생성'}
            </button>
          </div>
        </div>

        <div className="space-y-3">
          <label className="text-sm font-bold text-slate-400 uppercase tracking-tight block">결재 본문</label>
          <textarea 
            rows={10}
            value={content}
            onChange={(e) => setContent(e.target.value)}
            className="w-full px-6 py-6 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-mono text-sm leading-relaxed min-h-[300px]"
            placeholder="문서의 세부 내용을 입력하세요."
          />
        </div>

        {/* Attachment Section */}
        <div className="pt-8 border-t border-slate-100">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-tight">첨부 파일 (최대 3개)</h3>
            <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={attachments.length >= 3}
              className={`text-xs font-bold px-3 py-1.5 rounded-lg transition-colors border ${
                attachments.length >= 3 
                ? 'text-slate-300 border-slate-100 bg-slate-50 cursor-not-allowed' 
                : 'text-slate-600 hover:bg-slate-50 border-slate-200'
              }`}
            >
              📂 파일 선택
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              onChange={handleFileChange} 
              multiple 
            />
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
            {attachments.map((file) => (
              <div key={file.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-200">
                <div className="flex items-center gap-2 min-w-0">
                  <span className="text-lg">📄</span>
                  <div className="min-w-0">
                    <p className="text-xs font-bold text-slate-900 truncate">{file.name}</p>
                    <p className="text-[10px] text-slate-500">{formatFileSize(file.size)}</p>
                  </div>
                </div>
                <button 
                  onClick={() => removeAttachment(file.id)}
                  className="text-slate-400 hover:text-red-500 p-1"
                >
                  ✕
                </button>
              </div>
            ))}
            {attachments.length === 0 && (
              <p className="col-span-full text-xs text-slate-400 italic text-center py-4 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">
                첨부된 파일이 없습니다.
              </p>
            )}
          </div>
        </div>

        {/* Approval Line Section */}
        <div className="pt-8 border-t border-slate-100">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-tight">결재선 (결재/합의)</h3>
            <div className="flex gap-2">
              <button 
                onClick={() => setPickerConfig({ type: 'AGREEMENT' })}
                className="text-xs font-bold text-amber-600 hover:bg-amber-50 px-3 py-1.5 rounded-lg transition-colors border border-amber-100"
              >
                + 합의자 추가
              </button>
              <button 
                onClick={() => setPickerConfig({ type: 'APPROVER' })}
                className="text-xs font-bold text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors border border-blue-100"
              >
                + 결재자 추가
              </button>
            </div>
          </div>

          <div className="flex flex-wrap gap-4 items-center min-h-[60px] p-4 bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">
            <div className="flex items-center gap-2 bg-slate-100 px-4 py-2 rounded-xl border border-slate-200 shadow-sm">
              <div className="w-8 h-8 rounded-full bg-slate-300 flex items-center justify-center text-[10px] font-bold">ME</div>
              <div>
                <p className="text-xs font-bold text-slate-900">기안</p>
                <p className="text-[10px] text-slate-500">본인</p>
              </div>
            </div>

            {approvalLine.length > 0 && <span className="text-slate-300 text-xl">→</span>}

            {approvalLine.map((item, index) => (
              <React.Fragment key={item.user.id}>
                <div className={`group relative flex items-center gap-2 px-4 py-2 rounded-xl border shadow-sm transition-all ${
                  item.role === 'AGREEMENT' ? 'bg-amber-50 border-amber-200' : 'bg-white border-blue-200'
                }`}>
                  <div className={`w-8 h-8 rounded-full ${item.role === 'AGREEMENT' ? 'bg-amber-200' : 'bg-blue-100'}`}>
                    <img src={item.user.avatar} alt="" className="w-full h-full rounded-full" />
                  </div>
                  <div>
                    <div className="flex items-center gap-1">
                      <p className="text-xs font-bold text-slate-900">{item.user.name} {item.user.position}</p>
                      <span className={`text-[9px] px-1 rounded font-bold ${
                        item.role === 'AGREEMENT' ? 'bg-amber-200 text-amber-700' : 'bg-blue-100 text-blue-700'
                      }`}>
                        {item.role === 'AGREEMENT' ? '합의' : '결재'}
                      </span>
                    </div>
                    <p className="text-[10px] text-slate-500">{index + 1}차 단계</p>
                  </div>
                  <button 
                    onClick={() => removeFromLine(item.user.id)}
                    className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center text-[10px] opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                  >
                    ✕
                  </button>
                </div>
                {index < approvalLine.length - 1 && <span className="text-slate-300 text-xl">→</span>}
              </React.Fragment>
            ))}
          </div>
        </div>

        {/* Reference Section */}
        <div className="pt-8 border-t border-slate-100">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-tight">참조자</h3>
            <button 
              onClick={() => setPickerConfig({ type: 'REFERENCE' })}
              className="text-xs font-bold text-slate-600 hover:bg-slate-50 px-3 py-1.5 rounded-lg transition-colors border border-slate-200"
            >
              + 참조자 추가
            </button>
          </div>

          <div className="flex flex-wrap gap-2 items-center min-h-[50px] p-4 bg-slate-50/30 rounded-2xl border border-slate-100">
            {referenceUsers.map((user) => (
              <div key={user.id} className="group relative flex items-center gap-2 bg-white px-3 py-1.5 rounded-full border border-slate-200 shadow-sm">
                <div className="w-6 h-6 rounded-full bg-slate-100">
                  <img src={user.avatar} alt="" className="w-full h-full rounded-full" />
                </div>
                <span className="text-xs font-medium text-slate-700">{user.name} {user.position}</span>
                <button 
                  onClick={() => removeReference(user.id)}
                  className="w-4 h-4 bg-slate-200 text-slate-500 rounded-full flex items-center justify-center text-[10px] hover:bg-red-100 hover:text-red-500 transition-colors"
                >
                  ✕
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      {pickerConfig && (
        <UserPicker 
          onClose={() => setPickerConfig(null)} 
          onSelect={onUserSelected}
          excludeIds={[
            ...approvalLine.map(l => l.user.id),
            ...referenceUsers.map(u => u.id)
          ]}
        />
      )}
    </div>
  );
};

export default DraftView;

import React from 'react';
import { ApprovalDocument, ApprovalStatus } from '../types';

interface ApprovalDetailProps {
  doc: ApprovalDocument;
  onClose: () => void;
}

const ApprovalDetail: React.FC<ApprovalDetailProps> = ({ doc, onClose }) => {
  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const handleDownload = (data: string, name: string) => {
    const link = document.createElement('a');
    link.href = data;
    link.download = name;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-4xl h-[90vh] rounded-3xl shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200">
        <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between">
          <div>
            <span className="text-xs font-bold text-blue-600 uppercase tracking-wider">문서번호: {doc.id}</span>
            <h2 className="text-xl font-bold text-slate-900 mt-1">{doc.title}</h2>
          </div>
          <button 
            onClick={onClose}
            className="p-2 hover:bg-slate-100 rounded-full transition-colors"
          >
            ✕
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-10">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <h3 className="text-sm font-bold text-slate-400 uppercase">기안 정보</h3>
              <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <div className="w-12 h-12 rounded-full bg-blue-100 flex items-center justify-center text-xl font-bold text-blue-600 overflow-hidden">
                  {doc.author.avatar ? <img src={doc.author.avatar} alt="" /> : doc.author.name.charAt(0)}
                </div>
                <div>
                  <p className="font-bold text-slate-900">{doc.author.name} {doc.author.position}</p>
                  <p className="text-sm text-slate-500">{doc.author.department} · {new Date(doc.createdAt).toLocaleString()}</p>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="text-sm font-bold text-slate-400 uppercase">결재선 상태</h3>
              <div className="flex gap-4 overflow-x-auto pb-2">
                {doc.approvalLine.map((line, idx) => (
                  <div key={line.id} className="relative flex flex-col items-center flex-shrink-0">
                    <div className={`w-14 h-14 rounded-2xl flex flex-col items-center justify-center text-[10px] font-bold border-2 transition-all ${
                      line.status === 'APPROVED' ? 'bg-green-50 border-green-200 text-green-700' :
                      line.status === 'REJECTED' ? 'bg-red-50 border-red-200 text-red-700' :
                      line.role === 'AGREEMENT' ? 'bg-amber-50 border-amber-100 text-amber-600' :
                      'bg-slate-50 border-slate-200 text-slate-400'
                    }`}>
                      <span className="opacity-70 mb-1">{line.role === 'AGREEMENT' ? '합의' : '결재'}</span>
                      <span className="text-sm">{line.status === 'APPROVED' ? '승인' : line.status === 'REJECTED' ? '반려' : '대기'}</span>
                    </div>
                    <p className="text-xs font-bold mt-2 text-slate-900">{line.user.name}</p>
                    <p className="text-[10px] text-slate-500">{line.user.position}</p>
                    {idx < doc.approvalLine.length - 1 && (
                      <div className="absolute top-7 -right-3 w-4 h-[2px] bg-slate-200" />
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="text-sm font-bold text-slate-400 uppercase">본문 내용</h3>
            <div className="bg-white p-8 rounded-2xl border border-slate-200 min-h-[300px] whitespace-pre-wrap leading-relaxed text-slate-800 shadow-inner">
              {doc.content}
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="text-sm font-bold text-slate-400 uppercase">첨부 파일 ({doc.attachments.length})</h3>
            {doc.attachments.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {doc.attachments.map((file) => (
                  <button 
                    key={file.id}
                    onClick={() => handleDownload(file.data, file.name)}
                    className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:bg-blue-50 hover:border-blue-200 transition-all text-left"
                  >
                    <span className="text-2xl">📄</span>
                    <div className="min-w-0">
                      <p className="text-sm font-bold text-slate-900 truncate">{file.name}</p>
                      <p className="text-xs text-slate-500">{formatFileSize(file.size)}</p>
                    </div>
                    <span className="ml-auto text-blue-500 text-lg">↓</span>
                  </button>
                ))}
              </div>
            ) : (
              <div className="text-sm text-slate-400 italic">첨부된 파일이 없습니다.</div>
            )}
          </div>

          {doc.referenceUsers.length > 0 && (
            <div className="space-y-4">
              <h3 className="text-sm font-bold text-slate-400 uppercase">참조자</h3>
              <div className="flex flex-wrap gap-2">
                {doc.referenceUsers.map(user => (
                  <div key={user.id} className="flex items-center gap-2 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-200">
                    <img src={user.avatar} alt="" className="w-5 h-5 rounded-full" />
                    <span className="text-xs font-medium text-slate-600">{user.name} {user.position} ({user.department})</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="px-8 py-6 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
          {doc.status === ApprovalStatus.PENDING && (
            <>
              <button className="px-6 py-2.5 bg-white border border-slate-200 text-red-600 font-bold rounded-xl hover:bg-red-50 transition-colors shadow-sm">
                반려하기
              </button>
              <button className="px-8 py-2.5 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-100 transition-all active:scale-95">
                승인하기
              </button>
            </>
          )}
          <button 
            onClick={onClose}
            className="px-6 py-2.5 bg-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-300 transition-colors"
          >
            닫기
          </button>
        </div>
      </div>
    </div>
  );
};

