          ) : (
            <p className="mr-auto self-center text-sm font-medium text-slate-400 italic">
              {doc.status === ApprovalStatus.APPROVED ? '이미 승인 완료된 문서입니다.' : 
               doc.status === ApprovalStatus.REJECTED ? '반려된 문서입니다.' : 
               '현재 본인의 결재 순서가 아닙니다.'}
