import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DraftView from './components/DraftView';
import ApprovalDetail from './components/ApprovalDetail';
import AuthScreen from './components/AuthScreen';
import StaffStatus from './components/StaffStatus';
import { TabType, ApprovalDocument, ApprovalStatus, User, ApprovalLine, ApprovalRole, Attachment } from './types';
import { MOCK_DOCUMENTS, MOCK_USERS } from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [mockUsers, setMockUsers] = useState<User[]>(MOCK_USERS);
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [documents, setDocuments] = useState<ApprovalDocument[]>(MOCK_DOCUMENTS);
  const [selectedDoc, setSelectedDoc] = useState<ApprovalDocument | null>(null);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleSignUp = (newUser: User) => {
    setMockUsers([...mockUsers, newUser]);
    setCurrentUser(newUser);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    if (confirm('로그아웃 하시겠습니까?')) {
      setCurrentUser(null);
      setActiveTab('dashboard');
    }
  };

  const handleNewRequest = (
    title: string, 
    content: string, 
    templateId: string, 
    lineItems: { user: User, role: ApprovalRole }[], 
    references: User[],
    attachments: Attachment[]
  ) => {
    if (!currentUser) return;

    const approvalLine: ApprovalLine[] = lineItems.map((item, idx) => ({
      id: `al-${Date.now()}-${item.user.id}-${idx}`,
      user: item.user,
      status: 'PENDING',
      role: item.role
    }));

    const newDoc: ApprovalDocument = {
      id: `APP-${Math.floor(Math.random() * 100000)}`,
      title,
      content,
      templateId,
      author: currentUser,
      status: ApprovalStatus.PENDING,
      createdAt: new Date().toISOString(),
      approvalLine,
      referenceUsers: references,
      attachments: attachments
    };

    setDocuments([newDoc, ...documents]);
    setActiveTab('outbox');
  };

  const handleProcessApproval = (docId: string, status: 'APPROVED' | 'REJECTED') => {
    if (!currentUser) return;

    setDocuments(prevDocs => prevDocs.map(doc => {
      if (doc.id !== docId) return doc;

      // Find the current user's step in the approval line that is still pending
      const updatedLine = [...doc.approvalLine];
      const userStepIndex = updatedLine.findIndex(line => line.user.id === currentUser.id && line.status === 'PENDING');

      if (userStepIndex === -1) return doc;

      updatedLine[userStepIndex] = {
        ...updatedLine[userStepIndex],
        status: status,
        processedAt: new Date().toISOString()
      };

      let newDocStatus = doc.status;
      if (status === 'REJECTED') {
        newDocStatus = ApprovalStatus.REJECTED;
      } else {
        const isLastStep = updatedLine.every(line => line.status === 'APPROVED');
        if (isLastStep) {
          newDocStatus = ApprovalStatus.APPROVED;
        }
      }

      const updatedDoc = { ...doc, approvalLine: updatedLine, status: newDocStatus };
      if (selectedDoc?.id === docId) {
        setSelectedDoc(updatedDoc);
      }
      return updatedDoc;
    }));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard documents={documents} onSelectDoc={setSelectedDoc} currentUser={currentUser!} />;
      case 'draft':
        return <DraftView onSubmit={handleNewRequest} users={mockUsers} />;
      case 'staff':
        return <StaffStatus users={mockUsers} />;
      case 'inbox':
        const inboxDocs = documents.filter(doc => {
          const pendingStep = doc.approvalLine.find(l => l.status === 'PENDING');
          return pendingStep?.user.id === currentUser?.id;
        });

        return (
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm min-h-[500px]">
            <h2 className="text-2xl font-bold text-slate-800 mb-6">받은 결재함</h2>
            <div className="divide-y divide-slate-100">
              {inboxDocs.map((doc) => (
                <div 
                  key={doc.id} 
                  onClick={() => setSelectedDoc(doc)}
                  className="py-4 flex items-center justify-between hover:bg-slate-50 cursor-pointer px-4 rounded-xl transition-all hover:pl-6 border-l-4 border-l-blue-500 mb-2 bg-blue-50/30"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-lg bg-white flex items-center justify-center text-xl shadow-sm border border-slate-100">
                      {doc.templateId === 't1' ? '💰' : doc.templateId === 't2' ? '🏖️' : doc.templateId === 't3' ? '✈️' : '📄'}
                    </div>
                    <div>
                      <p className="font-bold text-slate-900">{doc.title}</p>
                      <p className="text-sm text-slate-500">{new Date(doc.createdAt).toLocaleDateString()} · 기안자: {doc.author.name}</p>
                    </div>
                  </div>
                  <span className="px-3 py-1 bg-blue-600 text-white rounded-full text-[10px] font-bold animate-pulse">
                    결재 대기
                  </span>
                </div>
              ))}
              {inboxDocs.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                  <span className="text-4xl mb-4">✨</span>
                  <p>지금은 결재할 문서가 없습니다.</p>
