  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <Dashboard 
            documents={documents} 
            onSelectDoc={setSelectedDoc} 
            currentUser={currentUser!}
            onRecommendationClick={handleRecommendationClick}
          />
        );
      case 'draft':
        return (
          <DraftView 
            onSubmit={handleNewRequest} 
            users={mockUsers} 
            preSelectedTemplateId={preSelectedTemplateId} 
          />
        );
      case 'staff':
        return <StaffStatus users={mockUsers} />;
      case 'inbox':
        const inboxDocs = documents.filter(doc => {
          const pendingStep = doc.approvalLine.find(l => l.status === 'PENDING');
          return pendingStep?.user.id === currentUser?.id;
        });

        return (
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm min-h-[500px]">
            <h2 className="text-2xl font-bold text-slate-800 mb-6">받은 결재함</h2>
            <div className="divide-y divide-slate-100">
              {inboxDocs.map((doc) => (
                <div 
                  key={doc.id} 
                  onClick={() => setSelectedDoc(doc)}
                  className="py-4 flex items-center justify-between hover:bg-slate-50 cursor-pointer px-4 rounded-xl transition-all hover:pl-6 border-l-4 border-l-blue-500 mb-2 bg-blue-50/30"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-lg bg-white flex items-center justify-center text-xl shadow-sm border border-slate-100">
                      {TEMPLATES.find(t => t.id === doc.templateId)?.icon || '📄'}
                    </div>
                    <div>
                      <p className="font-bold text-slate-900">{doc.title}</p>
                      <p className="text-sm text-slate-500">{new Date(doc.createdAt).toLocaleDateString()} · 기안자: {doc.author.name}</p>
                    </div>
                  </div>
                  <span className="px-3 py-1 bg-blue-600 text-white rounded-full text-[10px] font-bold animate-pulse">
                    결재 대기
                  </span>
                </div>
              ))}
              {inboxDocs.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                  <span className="text-4xl mb-4">✨</span>
                  <p>지금은 결재할 문서가 없습니다.</p>
                </div>
              )}
            </div>
          </div>
        );
      case 'outbox':
      case 'archived':
        const filteredDocs = activeTab === 'archived' 
          ? documents.filter(d => d.status === ApprovalStatus.APPROVED || d.status === ApprovalStatus.REJECTED)
          : documents.filter(d => d.status === ApprovalStatus.PENDING && d.author.id === currentUser?.id);

        return (
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm min-h-[500px]">
            <h2 className="text-2xl font-bold text-slate-800 mb-6">
              {activeTab === 'archived' ? '완료 문서함' : '보낸 결재함'}
            </h2>
            <div className="divide-y divide-slate-100">
              {filteredDocs.map((doc) => (
                <div 
                  key={doc.id} 
                  onClick={() => setSelectedDoc(doc)}
                  className="py-4 flex items-center justify-between hover:bg-slate-50 cursor-pointer px-4 rounded-xl transition-all hover:pl-6"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-lg bg-slate-50 flex items-center justify-center text-xl shadow-sm">
                      {TEMPLATES.find(t => t.id === doc.templateId)?.icon || '📄'}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-bold text-slate-900">{doc.title}</p>
                        <div className="flex gap-1">
                          {doc.referenceUsers.length > 0 && (
                            <span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded">참조 {doc.referenceUsers.length}</span>
                          )}
                          {doc.attachments.length > 0 && (
                            <span className="text-[10px] bg-blue-50 text-blue-500 px-1.5 py-0.5 rounded">첨부 {doc.attachments.length}</span>
                          )}
                        </div>
                      </div>
                      <p className="text-sm text-slate-500">{new Date(doc.createdAt).toLocaleDateString()} · {doc.author.name}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      doc.status === ApprovalStatus.APPROVED ? 'bg-green-100 text-green-700' :
                      doc.status === ApprovalStatus.REJECTED ? 'bg-red-100 text-red-700' :
                      'bg-blue-100 text-blue-700'
                    }`}>
                      {doc.status}
                    </span>
                  </div>
                </div>
              ))}
              {filteredDocs.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                  <span className="text-4xl mb-4">📂</span>
                  <p>문서가 없습니다.</p>
                </div>
              )}
            </div>
          </div>
        );
      default:
        return <div>준비 중입니다.</div>;
    }
  };

  if (!currentUser) {
    return <AuthScreen onLogin={handleLogin} onSignUp={handleSignUp} mockUsers={mockUsers} />;
  }

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans antialiased text-slate-900">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab) => {
          if (tab !== 'draft') setPreSelectedTemplateId(null);
          setActiveTab(tab);
        }} 
        onLogout={handleLogout}
      />

      <main className="flex-1 p-8 overflow-y-auto">
        <header className="flex items-center justify-end mb-8 relative z-30">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-full border border-slate-200 shadow-sm cursor-pointer hover:bg-slate-50 transition-colors">
              <span className="text-lg">🔔</span>
              <span className="bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">
                {documents.filter(doc => {
                  const pendingStep = doc.approvalLine.find(l => l.status === 'PENDING');
                  return pendingStep?.user.id === currentUser?.id;
                }).length}
              </span>
            </div>
            <div className="h-8 w-[1px] bg-slate-200" />

            <div className="relative">
              <div 
                onClick={() => setIsProfileMenuOpen(!isProfileMenuOpen)}
                className="flex items-center gap-3 cursor-pointer group hover:bg-slate-100/50 p-1 pr-3 rounded-full transition-all"
              >
                <div className="text-right">
                  <p className="text-sm font-bold text-slate-900">{currentUser.name} {currentUser.position}</p>
                  <p className="text-[10px] text-slate-500 font-medium">{currentUser.department}</p>
                </div>
                <img 
                  src={currentUser.avatar} 
                  alt="Profile" 
                  className="w-10 h-10 rounded-full border-2 border-white shadow-md group-hover:scale-105 transition-transform"
                />
              </div>

              {isProfileMenuOpen && (
                <>
                  <div 
                    className="fixed inset-0 z-40" 
                    onClick={() => setIsProfileMenuOpen(false)}
                  />
                  <div className="absolute top-full right-0 mt-3 w-56 bg-white border border-slate-200 shadow-2xl rounded-2xl py-2 z-50 animate-in fade-in slide-in-from-top-2">
                    <div className="px-4 py-3 border-b border-slate-100">
                      <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter mb-1">Signed in as</p>
                      <p className="text-sm font-bold text-slate-900">{currentUser.name}</p>
                      <p className="text-[10px] text-slate-500">{currentUser.phone}</p>
                    </div>
                    <button 
                      onClick={handleLogout}
                      className="w-full flex items-center gap-3 px-4 py-3 text-sm font-bold text-red-600 hover:bg-red-50 transition-colors text-left"
                    >
                      <span className="text-lg">🚪</span>
                      시스템 로그아웃
                    </button>
                  </div>
                </>
              )}
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>

      {selectedDoc && (
        <ApprovalDetail 
          doc={selectedDoc} 
          currentUser={currentUser}
          onProcessApproval={handleProcessApproval}
          onClose={() => setSelectedDoc(null)} 
        />
      )}
    </div>
  );
};

